    98→  console.log(`🔔 sendPushToMultipleDevices: Starting with ${devices.length} devices`);
    99→  
   100→  if (devices.length === 0) {
   101→    console.log(`🔔 sendPushToMultipleDevices: No devices, returning early`);
   102→    return { success: 0, failure: 0, invalidTokens: [] };
   103→  }
   104→  
